I need to retreat immediately from zombie ID 24 at 5 blocks and zombie ID 25 at 6.2 blocks. Let me create a retreat action and execute it:

new_action({
  "name": "retreat_to_safety",
  "description": "Retreat quickly away from nearest hostiles to establish safe distance",
  "args": [{ "targetDistance": 20, "maxRetreatSpeed": 2, "prioritizeHostiles": true }]
})

new_action({
  "name": "build_pillar_and_kite",
  "description": "Build a pillar upward then kite away from nearest hostile while maintaining distance for ranged attacks",
  "args": [{ "hostileId": 26, "pillarHeight": 3, "attackRange": 12, "maxTicks": 50 }]
})

new_action({
  "name": "kite_nearest_hostile",
  "description": "Back away from the nearest hostile while keeping distance for ranged attacks",
  "args": [{ "preferredDistance": 10, "retreatBlocks": 8, "maxTicks": 60 }]
})

new_action({
  "name": "emergency_retreat",
  "description": "Retreat 15+ blocks from all hostiles immediately when within 5 blocks",
  "args": [
    {
      "targetDistance": 15,
      "direction": "nearest",
      "priority": "escape"
    }
  ]
})
